-- Indexes
CREATE INDEX IF NOT EXISTS idx_osm_point_amenity ON public.planet_osm_point USING btree (amenity) WHERE (amenity IS NOT NULL);
CREATE INDEX IF NOT EXISTS idx_osm_point_highway ON public.planet_osm_point USING btree (highway) WHERE (highway IS NOT NULL);
CREATE INDEX IF NOT EXISTS idx_osm_point_natural ON public.planet_osm_point USING btree ("natural") WHERE ("natural" IS NOT NULL);
CREATE INDEX IF NOT EXISTS idx_osm_point_shop ON public.planet_osm_point USING btree (shop) WHERE (shop IS NOT NULL);
CREATE INDEX IF NOT EXISTS idx_osm_point_way ON public.planet_osm_point USING gist (way);
CREATE INDEX IF NOT EXISTS idx_osm_polygon_lei ON public.planet_osm_polygon USING btree (leisure) WHERE (leisure IS NOT NULL);
CREATE INDEX IF NOT EXISTS idx_osm_polygon_way ON public.planet_osm_polygon USING gist (way);
CREATE INDEX IF NOT EXISTS planet_osm_line_way_idx ON public.planet_osm_line USING gist (way) WITH (fillfactor='100');
CREATE INDEX IF NOT EXISTS planet_osm_point_way_idx ON public.planet_osm_point USING gist (way) WITH (fillfactor='100');
CREATE INDEX IF NOT EXISTS planet_osm_polygon_way_idx ON public.planet_osm_polygon USING gist (way) WITH (fillfactor='100');

-- Truncate before loading so seed is idempotent on populated databases
TRUNCATE TABLE planet_osm_polygon, planet_osm_point, planet_osm_line;

